145→
146→                match tool.execute(&call, &ctx) {
147→                    Ok(result) => {
148→                        let duration_ms = start.elapsed().as_millis() as u64;
149→                        span.record("mcp.duration_ms", duration_ms);
150→                        span.record("mcp.is_error", result.is_error);
151→                        info!(
152→                            tool = %tool_name,
153→                            duration_ms,
154→                            is_error = result.is_error,
155→                            "MCP tool call completed"
156→                        );
157→                        Ok(tool_result_to_call_result(&result))
158→                    }
159→                    Err(e) => {
160→                        let duration_ms = start.elapsed().as_millis() as u64;
161→                        span.record("mcp.duration_ms", duration_ms);
162→                        span.record("mcp.is_error", true);
163→                        warn!(
