//! use rmcp::ServiceExt;
//! use rmcp::transport::io::stdio;
//!
//! # async fn run() -> Result<(), Box<dyn std::error::Error>> {
//! let registry = ToolRegistry::default();
//! let server = PraxisMcpServer::new(registry);
//! server.serve(stdio()).await?.waiting().await?;
//! # Ok(())
