    pub fn registry(&self) -> &ToolRegistry {
        &self.registry
    }

    /// Build the MCP tool list from the registry.
    pub fn mcp_tools(&self) -> Vec<McpToolDef> {
        self.registry
            .definitions()
            .iter()
            .map(definition_to_mcp_tool)
            .collect()
    }
}

